// Build query parameters for time range filtering
const body = $('Webhook - Get Events').first().json.body || {};
const calendarName = body.calendar || $('Set Config').first().json.defaultCalendar;

// Default time range: fetch all events
let timeRange = '';
if (body.startDate || body.endDate) {
  // If specific dates provided, use them for filtering
  const start = body.startDate ? new Date(body.startDate) : new Date();
  const end = body.endDate ? new Date(body.endDate) : new Date(start.getTime() + 30 * 24 * 60 * 60 * 1000);

  const formatICalDate = (d) => {
    const year = d.getUTCFullYear();
    const month = String(d.getUTCMonth() + 1).padStart(2, '0');
    const day = String(d.getUTCDate()).padStart(2, '0');
    const hours = String(d.getUTCHours()).padStart(2, '0');
    const minutes = String(d.getUTCMinutes()).padStart(2, '0');
    const seconds = String(d.getUTCSeconds()).padStart(2, '0');
    return `${year}${month}${day}T${hours}${minutes}${seconds}Z`;
  };

  timeRange = `?start=${formatICalDate(start)}&end=${formatICalDate(end)}`;
}

const nextcloudUrl = $('Set Config').first().json.nextcloudUrl;
const nextcloudUser = $('Set Config').first().json.nextcloudUser;
const url = `${nextcloudUrl}/remote.php/dav/calendars/${nextcloudUser}/${calendarName}${timeRange}`;

return [{ json: { url, calendarName } }];

// Parse CalDAV XML response for VEVENT
const xml = $input.first().json.data || '';
const calendarName = $('Build URL').first().json.calendarName;

const events = [];

// Match VEVENT blocks
const veventMatches = xml.match(/<cal:VEVENT[^>]*>[\s\S]*?<\/cal:VEVENT>/gi) || [];

for (const vevent of veventMatches) {
  // Helper to extract value
  const extract = (tag) => {
    const match = vevent.match(new RegExp(`<cal:${tag}[^>]*>([^<]*)<\\/${tag}>`, 'i'));
    return match ? match[1] : null;
  };

  // Extract UID
  const uid = extract('UID');

  // Extract dates
  const dtstart = extract('DTSTART');
  const dtend = extract('DTEND');

  // Check if all-day event (VALUE=DATE format: YYYYMMDD)
  const isAllDay = dtstart && !dtstart.includes('T');

  // Parse iCal date to ISO
  const parseICalDate = (icalDate) => {
    if (!icalDate) return null;
    // YYYYMMDDTHHMMSSZ or YYYYMMDD
    if (icalDate.length === 8) {
      // All-day: YYYYMMDD
      return `${icalDate.substring(0, 4)}-${icalDate.substring(4, 6)}-${icalDate.substring(6, 8)}`;
    } else {
      // With time: YYYYMMDDTHHMMSSZ
      const year = icalDate.substring(0, 4);
      const month = icalDate.substring(4, 6);
      const day = icalDate.substring(6, 8);
      const hours = icalDate.substring(9, 11);
      const minutes = icalDate.substring(11, 13);
      const seconds = icalDate.substring(13, 15);
      return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}Z`;
    }
  };

  // Extract other properties
  const summary = extract('SUMMARY');
  const description = extract('DESCRIPTION');
  const location = extract('LOCATION');
  const status = extract('STATUS');
  const priority = extract('PRIORITY');
  const transparency = extract('TRANSP');
  const url = extract('URL');
  const categories = extract('CATEGORIES');
  const sequence = extract('SEQUENCE');

  // Extract RRULE
  const rruleMatch = vevent.match(/<cal:RRULE[^>]*>([^<]*)<\/cal:RRULE>/i);
  const recurrence = rruleMatch ? rruleMatch[1] : null;

  // Extract ATTENDEES
  const attendees = [];
  const attendeeMatches = vevent.match(/<cal:ATTENDEE[^>]*>([^<]*)<\/cal:ATTENDEE>/gi) || [];
  for (const att of attendeeMatches) {
    const email = att.match(/mailto:([^<]*)/i);
    const cn = att.match(/CN=([^;]*)/i);
    const partstat = att.match(/PARTSTAT=([^;]*)/i);
    if (email) {
      attendees.push({
        email: email[1],
        name: cn ? cn[1] : null,
        status: partstat ? partstat[1] : 'NEEDS-ACTION'
      });
    }
  }

  // Extract ORGANIZER
  const organizerMatch = vevent.match(/<cal:ORGANIZER[^>]*>([^<]*)<\/cal:ORGANIZER>/i);
  let organizer = null;
  if (organizerMatch) {
    const email = organizerMatch[1].match(/mailto:([^<]*)/i);
    const cn = organizerMatch[0].match(/CN=([^;]*)/i);
    organizer = {
      email: email ? email[1] : null,
      name: cn ? cn[1] : null
    };
  }

  // Extract EXDATE
  const exdateMatches = vevent.match(/<cal:EXDATE[^>]*>([^<]*)<\/cal:EXDATE>/gi) || [];
  const exceptions = exdateMatches.map(ex => {
    const date = ex.match(/>([^<]*)</);
    return date ? parseICalDate(date[1]) : null;
  }).filter(d => d);

  // Extract href for event URL
  const hrefMatch = vevent.match(/<d:href>([^<]*)<\/d:href>/i);
  const href = hrefMatch ? hrefMatch[1] : null;

  events.push({
    uid: uid || 'unknown',
    title: summary || 'Untitled',
    description: description || null,
    start: parseICalDate(dtstart),
    end: parseICalDate(dtend),
    allDay: isAllDay,
    location: location || null,
    status: status || 'CONFIRMED',
    priority: priority ? parseInt(priority) : null,
    transparency: transparency || 'OPAQUE',
    categories: categories ? categories.split(',').map(c => c.trim()) : [],
    recurrence: recurrence || null,
    attendees,
    organizer,
    exceptions,
    url: url || null,
    sequence: sequence ? parseInt(sequence) : 0,
    calendar: calendarName,
    href: href || null
  });
}

return [{ json: { events, count: events.length } }];
